class Solution {
    public int possibleStringCount(String word, int k) {
        int n = word.length();
        int[] count = new int[26];
        for (char c : word.toCharArray()) {
            count[c - 'a']++;
        }
        long ans = 1;
        for (int i = 0; i < 26; i++) {
            int freq = count[i];
            if (freq >= k) {
                ans = (ans * (freq - k + 1)) % 1000000007;
            }
        }
        return (int) ans;
    }
}
